        # 对除以 0 的情况进行单独处理。
        if result is None:
            print("除数不能为 0，请重新尝试。")
        else:
            # 正常输出计算结果。
            print(f"本次进行的是{op_name}，结果是：{result}")

        # 询问用户是否继续下一轮计算。
        again = input("是否继续计算？(y/n)：").strip().lower()
