import random


def main():
    print("=== 猜数字游戏 ===")
    target = random.randint(1, 100)
    attempts = 0

    while True:
        guess_text = input("请输入 1 到 100 之间的数字: ").strip()
        try:
            guess = int(guess_text)
        except ValueError:
            print("请输入有效的整数。")
            continue

        attempts += 1

        if guess < target:
            print("猜小了，再试试。")
        elif guess > target:
            print("猜大了，再试试。")
        else:
            print(f"恭喜你，猜对了！一共用了 {attempts} 次。")
            break


if __name__ == "__main__":
    main()

